#include <iostream>#include <string>#include <vector>#include <algorithm> using namespace std; void solve() {    int n;    cin >> n;    string s;    cin >> s;      vector<int> positions;    for (int i = 0; i < n; i++) {        if (s[i] == '1') {            positions.push_back(i);        }    }      if (positions.empty()) {        cout << "0 0" << endl;        return;    }     long long min_ones = 0;    long long max_ones = 0;     int i = 0;    int m = positions.size();     while (i < m) {        int start_pos = positions[i];        int last_pos = positions[i];                 while (i + 1 < m && positions[i+1] - positions[i] <= 2) {            i++;            last_pos = positions[i];        }          int k = last_pos - start_pos + 1;          max_ones += k;      min_ones += (k / 2) + 1;         i++;     }     cout << min_ones << " " << max_ones << endl;} int main() {    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int t;    cin >> t;    while (t--) {        solve();    }    return 0;}